      /**
       * Display storage query results based on mode and format
       */
      displayStorageResults(result, query) {
        switch (query.mode) {
          case "stats":
            displayStats(result);
            break;
          case "verify":
            displayVerification(result);
            break;
          case "urls":
            displaySignedUrls(result);
            break;
          case "metadata":
            displayMetadata(result);
            break;
          case "list":
          default:
            if (!query.outputFile) {
              console.log(import_chalk11.default.green(`
\u2705 Found ${result.count} files`));
              if (result.totalSize) {
                console.log(import_chalk11.default.gray(`   Total size: ${formatBytes(result.totalSize)}`));
              }
            }
            if (query.format === "table") {
              displayTable(result);
            } else if (query.format === "csv") {
              displayCSV(result);
            } else {
              displayJSON(result, query);
            }
            break;
        }
      }
